def meny():
  val = 0
  while val != 2:
    print("Meny\n1. Val 1.\n2. Avsluta.")
    try:
      val = int(input("Vad vill du göra?"))
    except ValueError:
      print("Inte ett giltigt menyval, vänligen försök igen")
      val = int(input("Vad vill du göra?"))

    if val == 1:
      print("Du valde 1.\n")

    elif val == 2:
      print("Programmet avslutas")

    else:
       print("Fel siffra, välj igen.")

meny()
